output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?attendanceNum WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  {
    ?series wdt:P527 ?game
  } UNION {
    ?game wdt:P361 ?series
  }
  ?game wdt:P1344 wd:Q213959 ; wdt:P1295 ?attendance .
  BIND(xsd:integer(?attendance) AS ?attendanceNum)
}
ORDER BY ASC(?attendanceNum)
LIMIT 1
OFFSET 4

